&lt;h3 id=&#34;Image&#34;&gt;Image&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;вҡ  The вҖңimages.domainsвҖқ configuration is deprecated. Please use вҖңimages.remotePatternsвҖқ configuration instead.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;const config = &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  webpack&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; (config&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt; isServer &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;) =&amp;gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;// https://nextjs.org/docs/messages/next-image-unconfigured-host&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;// https://stackoverflow.com/questions/71235874/how-to-allow-all-domains-for-image-nextjs-config&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  images&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    remotePatterns&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt; protocol&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;https&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; hostname&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**&amp;quot;&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt; protocol&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;https&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; hostname&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;xxx.com&amp;quot;&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// deprecated&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// domains: [&amp;quot;&amp;quot;],&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;next-auth&#34;&gt;next-auth&lt;/h3&gt;
&lt;h4 id=&#34;google-timeout&#34;&gt;google-timeout&lt;/h4&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title class_&#34;&gt;GoogleProvider&lt;/span&gt;(&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;clientId&lt;/span&gt;: env.&lt;span class=&#34;property&#34;&gt;GOOGLE_ID&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;clientSecret&lt;/span&gt;: env.&lt;span class=&#34;property&#34;&gt;GOOGLE_SECRET&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;httpOptions&lt;/span&gt;: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;timeout&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;40000&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;),&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight console&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[next-auth][error][SIGNIN_OAUTH_ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;https://next-auth.js.org/errors#signin_oauth_error outgoing request timed out after 3500ms &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  error: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    message: &amp;#x27;outgoing request timed out after 3500ms&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    stack: &amp;#x27;RPError: outgoing request timed out after 3500ms\n&amp;#x27; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#x27;    at eval (webpack-internal:///(rsc)/./node_modules/.pnpm/openid-client@5.6.5/node_modules/openid-client/lib/helpers/request.js:140:13)\n&amp;#x27; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#x27;    at async Server.requestListener (D:\\Repos\\AI-MOBI\\Dress\\ChatUp-AI-Dress-fullstack\\node_modules\\.pnpm\\next@14.2.5_react-dom@18.3.1_react@18.3.1__react@18.3.1\\node_modules\\next\\dist\\server\\lib\\start-server.js:141:13)&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    name: &amp;#x27;RPError&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  providerId: &amp;#x27;google&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  message: &amp;#x27;outgoing request timed out after 3500ms&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;https://next-auth.js.org/errors#signin_oauth_error  &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  error: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    message: &amp;#x27;&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    stack: &amp;#x27;AggregateError\n&amp;#x27; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#x27;    at internalConnectMultiple (node:net:1114:18)\n&amp;#x27; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#x27;    at afterConnectMultiple (node:net:1667:5)\n&amp;#x27; +&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#x27;    at TCPConnectWrap.callbackTrampoline (node:internal/async_hooks:130:17)&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    name: &amp;#x27;AggregateError&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  providerId: &amp;#x27;google&amp;#x27;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  message: &amp;#x27;&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;иҝҷжҳҜеӣ дёә auth иө°зҡ„жҳҜеҗҺз«ҜиҖҢдёҚжҳҜеүҚз«ҜжөҸи§ҲеҷЁ, next dev и·‘зҡ„жңҚеҠЎжІЎиө°зҪ‘з»ңд»ЈзҗҶ, жү“ејҖ tun жЁЎејҸе°ұиЎҢдәҶ&lt;/p&gt;
&lt;hr&gt;
&lt;h4 id=&#34;secret-missing&#34;&gt;secret-missing&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;Please define a &lt;code&gt;secret&lt;/code&gt; in production&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;providers&lt;/span&gt;: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title class_&#34;&gt;GoogleProvider&lt;/span&gt;(&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;clientId&lt;/span&gt;: env.&lt;span class=&#34;property&#34;&gt;GOOGLE_ID&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;clientSecret&lt;/span&gt;: env.&lt;span class=&#34;property&#34;&gt;GOOGLE_SECRET&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;httpOptions&lt;/span&gt;: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;timeout&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;40000&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// add this&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;secret&lt;/span&gt;: env.&lt;span class=&#34;property&#34;&gt;NEXTAUTH_SECRET&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;prisma&#34;&gt;prisma&lt;/h3&gt;
&lt;h4 id=&#34;client-deps-error&#34;&gt;client-deps-error&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;Prisma Client was generated for вҖңlinux-musl-openssl-3.0.xвҖқ, but the actual deployment required вҖңdebian-openssl-3.0.xвҖқ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;еҰӮдёӢеҠ дёҠ &lt;sup id=&#39;cite_ref-3&#39;&gt;&lt;a href=&#34;#cite_note-3&#34;&gt;[3]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight axapta&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;generator &lt;span class=&#34;keyword&#34;&gt;client&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    provider = &lt;span class=&#34;string&#34;&gt;&amp;quot;prisma-client-js&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// for dockerfile doploy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    binaryTargets = [&lt;span class=&#34;string&#34;&gt;&amp;quot;native&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;debian-openssl-3.0.x&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;table-does-not-exist&#34;&gt;table-does-not-exist&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;The table &lt;code&gt;main.account&lt;/code&gt; does not exist in the current database.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;зұ»дјјзҡ„й—®йўҳе…ҲзӣҙжҺҘиҜ•дёҖдёӢ &lt;code&gt;prisma db push&lt;/code&gt; жӣҙж–°дёӢж•°жҚ®еә“з»“жһ„&lt;/p&gt;
&lt;hr&gt;
&lt;h4 id=&#34;nextauth-mysql&#34;&gt;nextauth-mysql&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;Try signing in with a different account. &lt;br&gt;
next auth google login failed | prisma | mysql&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;йқһеёёеқ‘зҡ„й—®йўҳ, иҜҙжҳҜж— жі•зҷ»еҪ•, е®һйҷ…жҳҜж— жі•еңЁ db дёӯжҸ’е…Ҙж•°жҚ®, еҠЎеҝ…еҲ еә“йҮҚж–°е»әдёҖдёӘиҜ•иҜ•!!&lt;/p&gt;
&lt;h4 id=&#34;too-lang&#34;&gt;too-lang&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;NextAuth With Prisma for mysql specified key is too long&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;еӯ—ж®өеҠ дёҠ &lt;code&gt;@db.Text&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;usage&#34;&gt;usage&lt;/h2&gt;
&lt;h3 id=&#34;ж–Үд»¶дёҠдј -upload-file-image&#34;&gt;ж–Үд»¶дёҠдј -upload-file-image&lt;/h3&gt;
&lt;p&gt;еҰӮдҪ•е®һзҺ°еӣҫзүҮ/ж–Үд»¶дёҠдј ж“ҚдҪң&lt;/p&gt;
&lt;p&gt;дҪҝз”Ё t3app еҲӣе»әзҡ„йЎ№зӣ®, е…¶дёӯз”ЁеҲ°дәҶ tRPC, дҪҶеҫҲйҡҫеҸ—зҡ„жҳҜе®ғеҜ№ж–Үд»¶дј иҫ“дёҚж”ҜжҢҒ&lt;/p&gt;
&lt;p&gt;еҸӘиғҪз”Ё next еҺҹз”ҹ API router еҺ»еҶҷ RESTFUL &lt;sup id=&#39;cite_ref-1&#39;&gt;&lt;a href=&#34;#cite_note-1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;h4 id=&#34;form-data-parse&#34;&gt;form-data-parse&lt;/h4&gt;
&lt;p&gt;next еҗҺз«ҜеҰӮдҪ•и§Јжһҗ form ж јејҸеёҰж–Үд»¶зҡ„иҜ·жұӮ&lt;/p&gt;
&lt;p&gt;дёҖејҖе§ӢжҳҜжғіз”Ё form зӣҙжҺҘдёҠдј еӣҫзүҮж–Үд»¶, дҪҶжҳҜи§ЈжһҗиҝҮзЁӢдёӯжңүй—®йўҳ (з”ЁеҲ°зҡ„жҳҜ formidable )&lt;/p&gt;
&lt;p&gt;дёҚзҹҘйҒ“е“ӘйҮҢзҡ„й—®йўҳ, и§ЈжһҗеҮәжқҘзҡ„ж–Үд»¶дјҡеңЁ fields йҮҢ (string еҪўејҸ, еҫҲеҘҮжҖӘ), files дёәз©ә&lt;/p&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; config = &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;api&lt;/span&gt;: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// йңҖиҰҒзҰҒз”Ёй»ҳи®Өзҡ„&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;bodyParser&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// е°Ҷ form.parse е°ҒиЈ…еңЁдёҖдёӘ Promise дёӯ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;parseForm&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;params&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;req&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;NextApiRequest&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;): &lt;span class=&#34;title class_&#34;&gt;Promise&lt;/span&gt;&amp;lt;&amp;#123; &lt;span class=&#34;attr&#34;&gt;fields&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;Fields&lt;/span&gt;; &lt;span class=&#34;attr&#34;&gt;files&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;Files&lt;/span&gt; &amp;#125;&amp;gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Promise&lt;/span&gt;(&lt;span class=&#34;function&#34;&gt;(&lt;span class=&#34;params&#34;&gt;resolve, reject&lt;/span&gt;) =&amp;gt;&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; form = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;IncomingForm&lt;/span&gt;(&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;allowEmptyFiles&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;multiples&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;maxFileSize&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;, &lt;span class=&#34;comment&#34;&gt;// еўһеҠ ж–Үд»¶еӨ§е°ҸйҷҗеҲ¶, еҚ•дҪҚдёәеӯ—иҠӮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    form.&lt;span class=&#34;title function_&#34;&gt;parse&lt;/span&gt;(req, &lt;span class=&#34;function&#34;&gt;(&lt;span class=&#34;params&#34;&gt;err, fields, files&lt;/span&gt;) =&amp;gt;&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (err) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;title function_&#34;&gt;reject&lt;/span&gt;(err); &lt;span class=&#34;comment&#34;&gt;// еҰӮжһңи§ЈжһҗеҮәй”ҷпјҢreject иҝҷдёӘ promise&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;title function_&#34;&gt;resolve&lt;/span&gt;(&amp;#123; fields, files &amp;#125;); &lt;span class=&#34;comment&#34;&gt;// еҰӮжһңжҲҗеҠҹпјҢresolve иҝҷдёӘ promiseпјҢиҝ”еӣһи§ЈжһҗеҗҺзҡ„ж•°жҚ®&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h4 id=&#34;image-to-Buffer2string&#34;&gt;image-to-Buffer2string&lt;/h4&gt;
&lt;p&gt;иҪ¬дёәдҪҝз”Ё string еҺ»дј йҖ’еӣҫзүҮ&lt;/p&gt;
&lt;p&gt;еүҚз«Ҝ, е…Ҳд»ҺдәӢд»¶жӢҝеҲ° File еҜ№иұЎ, иҪ¬дёә ArrayBuffer, еҶҚиҪ¬дёә binary ж јејҸзҡ„ Buffer&lt;/p&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;handleImageChange&lt;/span&gt; = (&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;attr&#34;&gt;event&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;React&lt;/span&gt;.&lt;span class=&#34;title class_&#34;&gt;ChangeEvent&lt;/span&gt;&amp;lt;&lt;span class=&#34;title class_&#34;&gt;HTMLInputElement&lt;/span&gt;&amp;gt;&lt;/span&gt;) =&amp;gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; file = event.&lt;span class=&#34;property&#34;&gt;target&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;files&lt;/span&gt;?.[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!file) &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  file&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;arrayBuffer&lt;/span&gt;()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;then&lt;/span&gt;(&lt;span class=&#34;function&#34;&gt;(&lt;span class=&#34;params&#34;&gt;data&lt;/span&gt;) =&amp;gt;&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; textData = &lt;span class=&#34;title class_&#34;&gt;Buffer&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;from&lt;/span&gt;(data).&lt;span class=&#34;title function_&#34;&gt;toString&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;binary&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;еҗҺз«Ҝ:&lt;/p&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;interface&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;ResData&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;file&lt;/span&gt;: &lt;span class=&#34;built_in&#34;&gt;string&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// APIи·Ҝз”ұеӨ„зҗҶзЁӢеәҸ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;async&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;handler&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;params&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;req&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;NextApiRequest&lt;/span&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;params&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;res&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;NextApiResponse&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (req.&lt;span class=&#34;property&#34;&gt;method&lt;/span&gt; !== &lt;span class=&#34;string&#34;&gt;&amp;quot;POST&amp;quot;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; res.&lt;span class=&#34;title function_&#34;&gt;status&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;405&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;json&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;error&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;Method not allowed&amp;quot;&lt;/span&gt; &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; data = &lt;span class=&#34;title class_&#34;&gt;JSON&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;parse&lt;/span&gt;(req.&lt;span class=&#34;property&#34;&gt;body&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;string&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;ResData&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// console.log(data);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// е°ҶжҺҘж”¶еҲ°зҡ„еӯ—з¬ҰдёІиҪ¬дёә Buffer&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; buffer = &lt;span class=&#34;title class_&#34;&gt;Buffer&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;from&lt;/span&gt;(data.&lt;span class=&#34;property&#34;&gt;file&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;binary&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// &lt;span class=&#34;doctag&#34;&gt;TODO:&lt;/span&gt; дҝқеӯҳжҲ–иҖ…еӨ„зҗҶ Buffer&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; res.&lt;span class=&#34;title function_&#34;&gt;status&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;json&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;status&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;ok&amp;quot;&lt;/span&gt; &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (err) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// жҚ•иҺ·и§ЈжһҗиҝҮзЁӢдёӯеҸҜиғҪеҸ‘з”ҹзҡ„й”ҷиҜҜ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;error&lt;/span&gt;(err);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; res.&lt;span class=&#34;title function_&#34;&gt;status&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;500&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;json&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;error&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;Error parsing form data&amp;quot;&lt;/span&gt; &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;next-router-еӨҡйЎөйқўи·Ҝз”ұ&#34;&gt;next-router-еӨҡйЎөйқўи·Ҝз”ұ&lt;/h3&gt;
&lt;p&gt;дҪҝз”Ё t3app еҲӣе»әзҡ„йЎ№зӣ®дёҖиҲ¬дјҡеёҰжңү layout.tsx е’Ң page.tsx, дҪңз”ЁжҳҜиҝҷж ·:&lt;/p&gt;
&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;- app&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  - layout.tsx  &lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; жҺ§еҲ¶зҪ‘з«ҷж №иҠӮзӮ№йЎөйқўеёғеұҖ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  - page.tsx    &lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; жҺ§еҲ¶ &lt;span class=&#34;string&#34;&gt;&amp;#x27;/&amp;#x27;&lt;/span&gt; йЎөйқўи·Ҝз”ұ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  - login       &lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; ж–°е»ә &lt;span class=&#34;string&#34;&gt;&amp;#x27;/login&amp;#x27;&lt;/span&gt; йЎөйқў&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - layout.tsx&lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; еҗҢзҗҶ, ж №иҠӮзӮ№еҝ…йЎ»жңү, еӯҗйЎөйқўжІЎжңүд№ҹиЎҢ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - page.tsx  &lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; еҗҢзҗҶ, еӯҗйЎөйқўеҝ…йЎ»&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  - about       &lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt; ж–°е»ә &lt;span class=&#34;string&#34;&gt;&amp;#x27;/about&amp;#x27;&lt;/span&gt; йЎөйқў&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - page.tsx&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;еҸҜд»Ҙж–°е»әиҝҷдёӘж–Үд»¶, з„¶еҗҺи®ҝй—® &lt;code&gt;/login&lt;/code&gt; иҜ•дёҖиҜ•&lt;/p&gt;
&lt;figure class=&#34;highlight tsx&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// `app/login/page.tsx` is the UI for the `/login` URL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;Page&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;language-xml&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;h1&lt;/span&gt;&amp;gt;&lt;/span&gt;Hello, login page!&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;h1&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;payment-stripe&#34;&gt;payment-stripe&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;No such price: вҖҳprice_1PyqB006uMozVQ0qomnghCIoвҖҷ; a similar object exists in live mode, but a test mode key was used to make this request.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;priceId дёҺ stripe secret дёҚеҢ№й…ҚеҜјиҮҙ, жӯЈејҸдёҺжөӢиҜ• key дёҚйҖҡз”Ё&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;deployments&#34;&gt;deployments&lt;/h2&gt;
&lt;h3 id=&#34;vercel-file-read-write&#34;&gt;vercel-file-read-write&lt;/h3&gt;
&lt;p&gt;з”ЁдәҶд№ӢеҗҺжүҚж·ұеҲ»зҹҘйҒ“ vercel жҳҜдёӘ serverless е№іеҸ°, д№ҹе°ұжҳҜд»Јз ҒйҮҢдёҚиғҪз”Ё вҖңfsвҖқ&lt;/p&gt;
&lt;p&gt;еҪ“з„¶д№ҹдёҚжҳҜе®Ңе…ЁдёҚиғҪз”Ё, жҳҜеҸӘиҜ»зҠ¶жҖҒ (з”іиҜ·еҶҷе…ҘдјҡжҠҘй”ҷ: &lt;code&gt;EROFS: read-only file system&lt;/code&gt;)&lt;/p&gt;
&lt;p&gt;ж–Үд»¶еј•е…Ҙд№ҹжҜ”иҫғиӢӣеҲ» (йҖҡиҝҮ &lt;code&gt;../&lt;/code&gt; иҝҷз§ҚеҜје…ҘеҫҲе®№жҳ“еҮәзҺ° file not found) &lt;sup id=&#39;cite_ref-2&#39;&gt;&lt;a href=&#34;#cite_note-2&#34;&gt;[2]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://vercel.com/guides/how-can-i-use-files-in-serverless-functions&#34;&gt;жҢүе®ҳж–№е»әи®®&lt;/a&gt; жҳҜиҝҷз§Қ:&lt;/p&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;path.&lt;span class=&#34;title function_&#34;&gt;join&lt;/span&gt;(process.&lt;span class=&#34;title function_&#34;&gt;cwd&lt;/span&gt;(), &lt;span class=&#34;string&#34;&gt;&amp;quot;/public/img/xxx.png&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;еҰӮжһңзңҹйҒҮеҲ°йңҖиҰҒ &lt;code&gt;дёҙж—¶&lt;/code&gt; еҶҷе…Ҙзҡ„жғ…еҶө, еҸҜд»Ҙз”Ё &lt;code&gt;/tmp&lt;/code&gt; иҝҷдёӘи·Ҝеҫ„&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://stackoverflow.com/questions/70924414/vercel-read-only-file-system-chmod&#34;&gt;vercel read-only file system, chmod&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;еҸҰеӨ–жӣҙе»әи®®зҡ„еҒҡжі•жҳҜз”Ё Buffer дј йҖ’, дёҖиҲ¬дё»жөҒз¬¬дёүж–№еә“зҡ„иҫ“е…Ҙиҫ“е…ҘйғҪйҖӮй…ҚдәҶ (жҜ”еҰӮжҲ‘з”ЁеҲ°дәҶ Jimp)&lt;/p&gt;
&lt;h4 id=&#34;Jimp-watermark-ж·»еҠ ж°ҙеҚ°&#34;&gt;Jimp-watermark-ж·»еҠ ж°ҙеҚ°&lt;/h4&gt;
&lt;figure class=&#34;highlight ts&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; srcImg = &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Jimp&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;read&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;title class_&#34;&gt;Buffer&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;from&lt;/span&gt;(&lt;span class=&#34;title function_&#34;&gt;await&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;fetch&lt;/span&gt;(data.&lt;span class=&#34;property&#34;&gt;output&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;image_url&lt;/span&gt; ?? &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;)).&lt;span class=&#34;title function_&#34;&gt;arrayBuffer&lt;/span&gt;())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ж°ҙеҚ°еҠ еҲ°е·ҰдёӢи§’&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;srcImg.&lt;span class=&#34;title function_&#34;&gt;composite&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;Jimp&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;read&lt;/span&gt;(path.&lt;span class=&#34;title function_&#34;&gt;join&lt;/span&gt;(process.&lt;span class=&#34;title function_&#34;&gt;cwd&lt;/span&gt;(), &lt;span class=&#34;string&#34;&gt;&amp;quot;/public/img/watermark.png&amp;quot;&lt;/span&gt;)),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  srcImg.&lt;span class=&#34;title function_&#34;&gt;getHeight&lt;/span&gt;() - &lt;span class=&#34;number&#34;&gt;100&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;mode&lt;/span&gt;: &lt;span class=&#34;title class_&#34;&gt;Jimp&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;BLEND_SOURCE_OVER&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;opacitySource&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;opacityDest&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;0.8&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; resultBuffer = &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; srcImg.&lt;span class=&#34;title function_&#34;&gt;getBufferAsync&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;Jimp&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;MIME_JPEG&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h4 id=&#34;vercel-rewrites&#34;&gt;vercel-rewrites&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://vercel.com/docs/edge-network/rewrites&#34;&gt;https://vercel.com/docs/edge-network/rewrites&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;vercel еңЁйғЁзҪІдёҖдәӣ app ж—¶, дјҡеӯҳеңЁ 404 зҡ„й—®йўҳ&lt;/p&gt;
&lt;p&gt;еӣ дёә Vercel дёӯ &lt;code&gt;/xxx/&lt;/code&gt; е®һйҷ…и§Јжһҗең°еқҖдёә &lt;code&gt;xxx/index.html&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;иҖҢдёҚжҳҜ &lt;code&gt;/xxx.html&lt;/code&gt;, еҜјиҮҙи§Јжһҗй”ҷиҜҜ, еҸҜд»ҘеҸӮиҖғж–ҮжЎЈдҝ®еӨҚ:&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;&amp;quot;rewrites&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;&amp;quot;source&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/tags/:path(.*(?!/))&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;&amp;quot;destination&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/tags/:path.html&amp;quot;&lt;/span&gt; &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;aliyun-зҷҫзӮјжҚўиЈ…&#34;&gt;aliyun-зҷҫзӮјжҚўиЈ…&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;Download the media resource timed out during the data inspection process.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;иҝҷй—®йўҳжҳҜз”ұдәҺиө„жәҗй“ҫжҺҘзҰ»дёҠжө·жңүзӮ№иҝң/еӨӘеӨ§, иҺ·еҸ–и¶…ж—¶дәҶ, жҠҠж–Үд»¶жңҚеҠЎжҚўеҲ° ap-shanghai&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;centos7-е®қеЎ”-docker-CICD&#34;&gt;centos7-е®қеЎ”-docker-CICD&lt;/h3&gt;
&lt;p&gt;йҰ–е…Ҳйқўдёҙзҡ„й—®йўҳжҳҜ centos 7 еңЁдёҚеҚҮзә§зі»з»ҹзҡ„жғ…еҶөдёӢж— жі•зӣҙжҺҘе®үиЈ… nodejs 18 (nextjs жңҖдҪҺиҰҒжұӮ)&lt;/p&gt;
&lt;p&gt;жүҖд»ҘйҖүжӢ©з”Ё docker йғЁзҪІ, t3app иҮӘеёҰдәҶ Dockerfile&lt;/p&gt;
&lt;h4 id=&#34;е®һи·ө-CICD-nextjs-docker-dotenv&#34;&gt;е®һи·ө-CICD-nextjs-docker-dotenv&lt;/h4&gt;
&lt;p&gt;дёҖиҲ¬жғ…еҶөдёӢеүҚз«ҜйЎ№зӣ®зҡ„зҺҜеўғеҸҳйҮҸдёҚеӨӘдјҡеңЁ build ж—¶дҪҝз”Ё, еҰӮжһңеңЁд»Јз ҒйҮҢеҶҷзҺҜеўғеҸҳйҮҸеҲҮжҚў (JS/TS), дјҡеңЁ build ж—¶иў«зј–иҜ‘дёәйқҷжҖҒзҡ„, ж— жі•еңЁ run зҡ„ж—¶еҖҷеҠЁжҖҒеҸҳеҢ–&lt;/p&gt;
&lt;p&gt;жүҖд»Ҙз”Ё docker зј–иҜ‘ nextjs йЎ№зӣ®ж—¶, dockerfile дёҚз”ЁиҖғиҷ‘ .env, д№ҹдёҚе»әи®®е°Ҷ .env жү“еҢ…еңЁ docker image дёӯ&lt;/p&gt;
&lt;p&gt;build дёәдёҖдёӘ docker image, жҠҠ .env еӨҚеҲ¶еҲ°дёҚеҗҢзҺҜеўғеҶҚиҝҗиЎҢ&lt;/p&gt;
&lt;hr&gt;
&lt;h4 id=&#34;еҸҢеј•еҸ·й—®йўҳ&#34;&gt;еҸҢеј•еҸ·й—®йўҳ&lt;/h4&gt;
&lt;p&gt;.env дёӯжӯЈеёёи®ҫзҪ®дәҶ: &lt;code&gt;NEXTAUTH_URL=&amp;quot;http://localhost:3000&amp;quot;&lt;/code&gt;, дҪҶиҝҗиЎҢж—¶жҠҘй”ҷдәҶ&lt;/p&gt;
&lt;p&gt;вқҢ Invalid environment variables: { NEXTAUTH_URL: [ вҖҳInvalid urlвҖҷ ] }&lt;/p&gt;
&lt;p&gt;е®һйҷ… .env зҡ„и§Јжһҗд№ҹи·ҹйғЁзҪІзҺҜеўғжңүиҒ”зі», жҲ‘з”Ёзҡ„жҳҜ docker run --env-file .env зҡ„еҪўејҸжҸ’е…ҘзҺҜеўғеҸҳйҮҸ, docker дёӯе®һйҷ…жҳҜиҝҷж ·и§Јжһҗзҡ„&lt;/p&gt;
&lt;figure class=&#34;highlight awk&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;25&amp;quot;&lt;/span&gt; : &lt;span class=&#34;string&#34;&gt;&amp;quot;NEXTAUTH_URL=&amp;quot;&lt;/span&gt;http:&lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt;localhost:&lt;span class=&#34;number&#34;&gt;3000&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;26&amp;quot;&lt;/span&gt; : &lt;span class=&#34;string&#34;&gt;&amp;quot;NEXT_PUBLIC_NEXTAUTH_URL=&amp;quot;&lt;/span&gt;http:&lt;span class=&#34;regexp&#34;&gt;//&lt;/span&gt;localhost:&lt;span class=&#34;number&#34;&gt;3000&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;27&amp;quot;&lt;/span&gt; : &lt;span class=&#34;string&#34;&gt;&amp;quot;PATH=/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;28&amp;quot;&lt;/span&gt; : &lt;span class=&#34;string&#34;&gt;&amp;quot;SSL_CERT_FILE=/etc/ssl/certs/ca-certificates.crt&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;29&amp;quot;&lt;/span&gt; : &lt;span class=&#34;string&#34;&gt;&amp;quot;NEXT_SHARP_PATH=/app/node_modules/sharp&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;дҪҶеҸҜи§Ғзҡ„й—®йўҳжҳҜеј•еҸ·иў«жҸҗеүҚжҲӘжӯў, жүҖд»ҘеҜјиҮҙзЁӢеәҸж— жі•еј•еҲ°еҸҳйҮҸ&lt;/p&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еҖҹзү©иЎЁ&#34;&gt;еҖҹзү©иЎЁ&lt;/h2&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-1&#39; href=&#39;#cite_ref-1&#39;&gt;[1]&lt;/a&gt;: &lt;a href=&#34;https://stackoverflow.com/questions/76105855/send-blob-image-from-frontend-to-backend-with-nextjs-and-trpc-t3-stack&#34;&gt;https://stackoverflow.com/questions/76105855/send-blob-image-from-frontend-to-backend-with-nextjs-and-trpc-t3-stack&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-2&#39; href=&#39;#cite_ref-2&#39;&gt;[2]&lt;/a&gt;: &lt;a href=&#34;https://medium.com/@nksCodingLearnings/how-to-read-and-write-files-in-next-js-on-a-vercel-deployed-website-c1e9ea606cb6&#34;&gt;How to Read and Write Files in Next.js on a Vercel Deployed Website&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-3&#39; href=&#39;#cite_ref-3&#39;&gt;[3]&lt;/a&gt;: &lt;a href=&#34;https://stackoverflow.com/questions/71600978/missingsecret-missingsecreterror-please-define-a-secret-in-production&#34;&gt;MissingSecret [MissingSecretError]: Please define a &lt;code&gt;secret&lt;/code&gt; in production&lt;/a&gt;&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;
